// Initialise enrichedVars avec une variable DemoVar si absent
let enrichedVars = global.get("enrichedVars", "file") || {};

if (!enrichedVars.DemoVar) {
    enrichedVars.DemoVar = {
        nomVarG: "DemoVar",
        abbrVarG: "DVar",
        descriptionVarG: "Variable de démo avec différents types de propriétés",
        dateUpdateVarG: new Date().toISOString(),
        instances: ["*", "inst1", "inst2"],
        proprietes: [
            {
                nomP: "nom",
                abbrP: "nm",
                typeP: "string",
                schema: null,
                valeurs: { "*": "Inconnu", inst1: "Alice", inst2: "Bob" }
            },
            {
                nomP: "age",
                abbrP: "ag",
                typeP: "number",
                schema: null,
                valeurs: { "*": 0, inst1: 30, inst2: 25 }
            },
            {
                nomP: "actif",
                abbrP: "act",
                typeP: "boolean",
                schema: null,
                valeurs: { "*": true, inst1: false, inst2: true }
            },
            {
                nomP: "adresse",
                abbrP: "adr",
                typeP: "object",
                schema: [
                    { nomSsP: "rue", typeSsP: "string" },
                    { nomSsP: "ville", typeSsP: "string" }
                ],
                valeurs: {
                    "*": { rue: "?", ville: "?" },
                    inst1: { rue: "12 rue A", ville: "Paris" },
                    inst2: { rue: "34 rue B", ville: "Lyon" }
                }
            }
        ]
    };
    global.set("enrichedVars", enrichedVars, "file");
}

// Définit DemoVar comme variable sélectionnée par défaut
flow.set("varSelected", "DemoVar");

return { payload: "DemoVar prêt" };

// Prépare le tableau principal des propriétés
let varSelected = flow.get("varSelected") || null;
let enriched = global.get("enrichedVars","file") || {};
let variable = enriched[varSelected] || {};

if (!varSelected || !variable.proprietes) {
    msg.payload = { proprietes: [], instances: [] };
    msg.view = "tableau";
    msg.info = "⚠️ Aucune variable sélectionnée.";
    return msg;
}

let instances = variable.instances || ["*"];
let proprietes = variable.proprietes.map(p => {
    let valeurs = p.valeurs || {};
    return {
        nomP: p.nomP,
        abbrP: p.abbrP,
        typeP: p.typeP,
        schema: p.schema || null,
        defaut: valeurs["*"], // valeur par défaut
        valeurs: valeurs
    };
});

msg.payload = {
    variable: variable,
    proprietes: proprietes,
    instances: instances.filter(i => i !== "*") // on cache * côté tableau
};

msg.view = "tableau";
return msg;

// Router les actions du frontend vers les bons handlers
// sorties: [openEditor, deleteProp, saveProp, cancel]

const topic = msg.topic;

if (!topic) return null;

switch (topic) {
  case "openEditor":
    flow.set("propSelected", JSON.parse(JSON.stringify(msg.prop || {})));
    flow.set("propOriginalName", (msg.prop && msg.prop.nomP) || null);
    return [msg, null, null, null];

  case "deleteProp":
    msg.prop = JSON.parse(JSON.stringify(msg.prop || {}));
    return [null, msg, null, null];

  case "save":
    msg.prop = JSON.parse(JSON.stringify(msg.prop || {}));
    msg.saveKind = msg.saveKind || "base";
    msg.originalName = flow.get("propOriginalName") || (msg.prop && msg.prop.nomP);
    return [null, null, msg, null];

  case "cancel":
    return [null, null, null, { topic: "refresh", view: "tableau" }];

  default:
    return null;
}

// Suppression avec backup automatique
let varSelected = flow.get("varSelected");
let enriched = global.get("enrichedVars","file") || {};
let variable = enriched[varSelected];

if (!variable || !msg.prop || !msg.prop.nomP) {
  msg.info = "❌ Données manquantes pour supprimer.";
  return msg;
}

let backups = global.get("enrichedVars_backups","file") || [];
backups.push({ ts: new Date().toISOString(), snapshot: JSON.parse(JSON.stringify(enriched)) });
global.set("enrichedVars_backups", backups, "file");

let idx = variable.proprietes.findIndex(p => p.nomP === msg.prop.nomP);
if (idx === -1) {
  msg.info = "⚠️ Propriété introuvable.";
  return { payload: null, info: msg.info };
}

variable.proprietes.splice(idx, 1);
enriched[varSelected] = variable;
global.set("enrichedVars", enriched, "file");

msg.info = `✅ Propriété supprimée : ${msg.prop.nomP}`;
return { topic: "refresh", view: "tableau", info: msg.info };

// Sauvegarde une propriété (base | schema | valeurs)
let varSelected = flow.get("varSelected");
let enriched = global.get("enrichedVars","file") || {};
let variable = enriched[varSelected];

if (!variable || !msg.prop) {
  msg.info = "❌ Données incomplètes pour la sauvegarde.";
  return msg;
}

let originalName = msg.originalName || (flow.get("propSelected")||{}).nomP;
let proprietes = variable.proprietes || [];
let idx = proprietes.findIndex(p => p.nomP === originalName);

if (idx === -1 && msg.saveKind === "base") {
  let newProp = {
    nomP: msg.prop.nomP,
    abbrP: msg.prop.abbrP || "",
    typeP: msg.prop.typeP || "string",
    schema: msg.prop.schema || null,
    valeurs: {}
  };
  (variable.instances || ["*"]).forEach(i => { newProp.valeurs[i] = null; });
  proprietes.push(newProp);
  idx = proprietes.length - 1;
}

if (idx === -1) {
  msg.info = "❌ Propriété introuvable.";
  return msg;
}

let backups = global.get("enrichedVars_backups","file") || [];
backups.push({ ts: new Date().toISOString(), snapshot: JSON.parse(JSON.stringify(enriched)) });
global.set("enrichedVars_backups", backups, "file");

if (msg.saveKind === "base") {
  proprietes[idx].nomP = msg.prop.nomP;
  proprietes[idx].abbrP = msg.prop.abbrP;
  proprietes[idx].typeP = msg.prop.typeP;
}
else if (msg.saveKind === "schema") {
  proprietes[idx].schema = msg.prop.schema || [];
}
else if (msg.saveKind === "valeurs") {
  proprietes[idx].valeurs = msg.prop.valeurs || {};
}

enriched[varSelected].proprietes = proprietes;
global.set("enrichedVars", enriched, "file");

flow.set("propSelected", proprietes[idx]);

msg.info = `✅ Propriété ${proprietes[idx].nomP} sauvegardée (${msg.saveKind}).`;
return { topic: "refresh", view: "tableau", info: msg.info };
